import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{o as n,c as t,d as a}from"./app.e26ab0af.js";const i={},s=a(`<p>By default, the CMS has its environment set to <strong>&quot;production&quot;</strong>, which is very different from past versions. Due to this, in order to develop modules or some new characteristic for the CMS and to be able to see the possible <strong>errors when developing</strong>, you will have to modify this parameter depending on the webserver.</p><h2 id="how-to-change-the-environment-parameter-in-apache" tabindex="-1"><a class="header-anchor" href="#how-to-change-the-environment-parameter-in-apache" aria-hidden="true">#</a> How to change the environment parameter in Apache?</h2><p>If you installed the CMS in <strong>Apache</strong>, look in your main folder for the <code>.htaccess</code> file and edit it by adding the following line at the end of the file:</p><div class="language-apacheconf ext-apacheconf line-numbers-mode"><pre class="language-apacheconf"><code><span class="token directive-inline property">SetEnv</span> CI_ENV development
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="custom-container warning"><p class="custom-container-title">NOTICES</p><p>Remember to remove this line when using the CMS in production environments.</p></div><h2 id="how-to-change-the-environment-parameter-in-nginx" tabindex="-1"><a class="header-anchor" href="#how-to-change-the-environment-parameter-in-nginx" aria-hidden="true">#</a> How to change the environment parameter in Nginx?</h2><p>If you installed the CMS in <strong>Nginx</strong>, on your <strong>server block</strong> (virtual host) edit it by adding the following line:</p><div class="language-nginx ext-nginx line-numbers-mode"><pre class="language-nginx"><code><span class="token directive"><span class="token keyword">server</span></span> <span class="token punctuation">{</span>
    <span class="token directive"><span class="token keyword">location</span> ~ \\.php$</span> <span class="token punctuation">{</span>
        <span class="token directive"><span class="token keyword">fastcgi_param</span> CI_ENV <span class="token string">&quot;development&quot;</span></span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="highlight-lines"><br><br><div class="highlight-line">\xA0</div><br><br></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="custom-container warning"><p class="custom-container-title">NOTICES</p><p>Remember to remove this line when using the CMS in production environments.</p></div>`,9),o=[s];function r(c,l){return n(),t("div",null,o)}var h=e(i,[["render",r],["__file","environment.html.vue"]]);export{h as default};
